const sedeInput = document.getElementById("Sede");
const fechaInput = document.getElementById("fecha");
const numeroActa = document.getElementById("numeroActa");

function obtenerNumeroActa(registro) {
    return registro.numeroActa || "";
}
function generarNumeroActa() {

    const sede = sedeInput.value.trim();
    const fecha = fechaInput.value;

    // Validar datos
    if (!sede || !fecha) {
        numeroActa.value = "";
        return;
    }

    // Primera letra de la sede
    const letra = sede.charAt(0).toUpperCase();

    // Separar fecha
    const partes = fecha.split("-");

    const anio = partes[0];
    const mes = partes[1];
    const dia = partes[2];

    // El correlativo será el número actual de registros + 1
    const correlativo = registros.length + 1;

    // Formato: [Letra][Mes][Año]-[Correlativo]
    const codigo = `${letra}${mes}${anio}-${correlativo}`;

    numeroActa.value = codigo;
}

// Eventos
sedeInput.addEventListener("change", generarNumeroActa);
fechaInput.addEventListener("change", generarNumeroActa);

const marcaSelect = document.getElementById("Marca");
const otraMarcaInput = document.getElementById("otraMarcaInput");
const cantidadInput = document.getElementById("Cantidad");
const replicarCheckbox = document.getElementById("replicarDatos");
const equiposAdicionalesContainer = document.getElementById("equipos-adicionales-container");

const dispositivoEntregaSelect = document.getElementById("dispositivoEntrega");
const otroDispositivoEntregaInput = document.getElementById("otroDispositivoEntrega");

dispositivoEntregaSelect.addEventListener("change", function () {
    if (this.value === "Otro") {
        otroDispositivoEntregaInput.style.display = "block";
        otroDispositivoEntregaInput.required = true;
    } else {
        otroDispositivoEntregaInput.style.display = "none";
        otroDispositivoEntregaInput.required = false;
        otroDispositivoEntregaInput.value = "";
    }
});

marcaSelect.addEventListener("change", function () {
    if (this.value === "Otra") {
        otraMarcaInput.style.display = "block";
        otraMarcaInput.required = true;
    } else {
        otraMarcaInput.style.display = "none";
        otraMarcaInput.required = false;
        otraMarcaInput.value = "";
    }
});

function replicarValores() {
    if (!replicarCheckbox || !replicarCheckbox.checked) return;

    const dispositivoVal = dispositivoEntregaSelect.value;
    const otroDispositivoVal = otroDispositivoEntregaInput.value;
    const marcaVal = marcaSelect.value;
    const otraMarcaVal = otraMarcaInput.value;
    const modeloVal = document.getElementById("Modelo").value;
    const serialVal = document.getElementById("Serial").value;

    const dispositivosExtra = document.querySelectorAll(".dispositivo-extra");
    const marcasExtra = document.querySelectorAll(".marca-extra");
    const modelosExtra = document.querySelectorAll(".modelo-extra");
    const serialsExtra = document.querySelectorAll(".serial-extra");

    dispositivosExtra.forEach(el => {
        el.value = dispositivoVal;
        const otraInput = el.parentElement.querySelector(".otro-dispositivo-extra-input");
        if (dispositivoVal === "Otro") {
            otraInput.style.display = "block";
            otraInput.required = true;
            otraInput.value = otroDispositivoVal;
        } else {
            otraInput.style.display = "none";
            otraInput.required = false;
            otraInput.value = "";
        }
    });

    marcasExtra.forEach(el => {
        el.value = marcaVal;
        const otraInput = el.parentElement.querySelector(".otra-marca-extra-input");
        if (marcaVal === "Otra") {
            otraInput.style.display = "block";
            otraInput.required = true;
            otraInput.value = otraMarcaVal;
        } else {
            otraInput.style.display = "none";
            otraInput.required = false;
            otraInput.value = "";
        }
    });

    modelosExtra.forEach(el => {
        el.value = modeloVal;
    });

    serialsExtra.forEach(el => {
        el.value = serialVal;
    });
}

