cantidadInput.addEventListener("change", actualizarEquiposAdicionales);
cantidadInput.addEventListener("input", actualizarEquiposAdicionales);
replicarCheckbox.addEventListener("change", function () {
    if (this.checked) {
        replicarValores();
    }
});

dispositivoEntregaSelect.addEventListener("change", replicarValores);
otroDispositivoEntregaInput.addEventListener("input", replicarValores);
marcaSelect.addEventListener("change", replicarValores);
