document.getElementById("Serial").addEventListener("input", replicarValores);

function formatearFecha(fechaStr) {
    if (!fechaStr) return "";
    const partes = fechaStr.split("-");
    if (partes.length !== 3) return fechaStr;
    return `${partes[2]}-${partes[1]}-${partes[0]}`;
}

const tipoSelect = document.getElementById("Tipo");
const camposEquipo = document.querySelectorAll(".campo-equipo");
const camposComponentes = document.querySelectorAll(".campo-componentes");
const camposPrestamo = document.querySelectorAll(".campo-prestamo");
const camposDevolucion = document.querySelectorAll(".campo-devolucion");

tipoSelect.addEventListener("change", function () {
    // Ocultar todo primero
    const todosLosCampos = [...camposEquipo, ...camposComponentes, ...camposPrestamo, ...camposDevolucion];
    todosLosCampos.forEach(campo => campo.style.display = "none");

    // Mostrar según selección
    if (this.value === "Acta De Entrega") {
        camposEquipo.forEach(campo => {
            if (campo.id === "equipos-adicionales-container" || campo.classList.contains("replicar-container")) {
                const cantidad = parseInt(cantidadInput.value) || 1;
                if (cantidad > 1) {
                    campo.style.display = campo.classList.contains("replicar-container") ? "flex" : "block";
                } else {
                    campo.style.display = "none";
                }
            } else {
                campo.style.display = "block";
            }
        });
    } else if (this.value === "Acta Componentes") {
        camposComponentes.forEach(campo => campo.style.display = "block");
    } else if (this.value === "Acta Prestamo") {
        camposPrestamo.forEach(campo => campo.style.display = "block");
    } else if (this.value === "Acta De Devolucion") {
        camposDevolucion.forEach(campo => campo.style.display = "block");
    }
});

// Establecer fecha actual por defecto
function establecerFechaActual() {
    const hoy = new Date();
    const anio = hoy.getFullYear();
    const mes = String(hoy.getMonth() + 1).padStart(2, '0');
    const dia = String(hoy.getDate()).padStart(2, '0');
    fechaInput.value = `${anio}-${mes}-${dia}`;
}

establecerFechaActual();

function exportarExcel() {

    console.log("Click EXCEL");
    const worksheet = XLSX.utils.json_to_sheet(registros);

    const workbook = XLSX.utils.book_new();

    XLSX.utils.book_append_sheet(workbook, worksheet, "Registros");

    XLSX.writeFile(workbook, "registros.xlsx");
}

let registros = JSON.parse(localStorage.getItem("registros")) || [];
let paginaActual = 1;
const registrosPorPagina = 7;

mostrarRegistros();

// Busqueda
document.getElementById("busqueda").addEventListener("input", function (e) {
    paginaActual = 1; // Resetear a la primera página al buscar
    mostrarRegistros();
});

formulario.addEventListener("submit", function (e) {

    e.preventDefault();

    const tipo = document.getElementById("Tipo").value;
    let equipos = [];

    if (tipo === "Acta De Entrega") {
        const cantidad = parseInt(cantidadInput.value) || 1;

        // El primer equipo
        let dispositivo1 = document.getElementById("dispositivoEntrega").value;
        if (dispositivo1 === "Otro") {
            dispositivo1 = document.getElementById("otroDispositivoEntrega").value;
        }
        let marca1 = document.getElementById("Marca").value;
        if (marca1 === "Otra") {
            marca1 = document.getElementById("otraMarcaInput").value;
        }
        equipos.push({
            Dispositivo: dispositivo1,
            Marca: marca1,
            Modelo: document.getElementById("Modelo").value,
            Serial: document.getElementById("Serial").value,
            Pin: document.getElementById("Pin").value
        });

        // Equipos adicionales
        if (cantidad > 1) {
            const cards = document.querySelectorAll(".equipo-extra-card");
            cards.forEach(card => {
                let dispositivo = card.querySelector(".dispositivo-extra").value;
                if (dispositivo === "Otro") {
                    dispositivo = card.querySelector(".otro-dispositivo-extra-input").value;
                }
                let marca = card.querySelector(".marca-extra").value;
                if (marca === "Otra") {
                    marca = card.querySelector(".otra-marca-extra-input").value;
                }
                equipos.push({
                    Dispositivo: dispositivo,
                    Marca: marca,
                    Modelo: card.querySelector(".modelo-extra").value,
                    Serial: card.querySelector(".serial-extra").value,
                    Pin: card.querySelector(".pin-extra").value
                });
            });
        }
    }

    const registro = {
        nombre: document.getElementById("nombre").value,
        fecha: document.getElementById("fecha").value,
        Cargo: document.getElementById("Cargo").value,
        Sede: document.getElementById("Sede").value,
        Area: document.getElementById("Area").value,
        Tecnico: document.getElementById("Tecnico").value,
        Tipo: tipo,

        // Campos Acta De Entrega (root levels for backward compatibility)
        DispositivoEntrega: equipos[0] ? equipos[0].Dispositivo : "",
        Marca: equipos[0] ? equipos[0].Marca : "",
        Modelo: equipos[0] ? equipos[0].Modelo : "",
        Serial: equipos[0] ? equipos[0].Serial : "",
        Pin: equipos[0] ? equipos[0].Pin : "",

        // Todos los equipos
        equipos: equipos,

        // Campos Acta Componentes
        Dispositivo: document.getElementById("dispositivo").value,
        ModeloComponente: document.getElementById("modeloComponente").value,
        SerialComponente: document.getElementById("serialComponente").value,

        // Campos Acta Prestamo
        FechaDevolucion: document.getElementById("fechaDevolucion").value,
        DispositivoPrestamo: document.getElementById("dispositivoPrestamo").value,
        SerialPrestamo: document.getElementById("serialPrestamo").value,

        // Campos Acta De Devolucion
        EquipoDevolucion: document.getElementById("equipoDevolucion").value,
        ModeloDevolucion: document.getElementById("modeloDevolucion").value,
        SerialDevolucion: document.getElementById("serialDevolucion").value,

        numeroActa: document.getElementById("numeroActa").value,
        observaciones: document.getElementById("observaciones").value
    };

    registros.push(registro);

    localStorage.setItem("registros", JSON.stringify(registros));

    mostrarRegistros();

    formulario.reset();
    otraMarcaInput.style.display = "none";
    otraMarcaInput.required = false;
    otroDispositivoEntregaInput.style.display = "none";
    otroDispositivoEntregaInput.required = false;

    // Reset de equipos adicionales y checkbox de replicación
    equiposAdicionalesContainer.innerHTML = "";
    equiposAdicionalesContainer.style.display = "none";
    replicarCheckbox.checked = true;

    const todosLosCampos = [...camposEquipo, ...camposComponentes, ...camposPrestamo, ...camposDevolucion];
    todosLosCampos.forEach(campo => campo.style.display = "none");
    establecerFechaActual();
    generarNumeroActa(); // Regenerar el acta para el nuevo registro
});

document.getElementById("btnLimpiar").addEventListener("click", function () {
    if (confirm("¿Estás seguro de que deseas eliminar todos los registros?")) {
        registros = [];
        localStorage.removeItem("registros");
        paginaActual = 1;
        mostrarRegistros();
    }
});

function mostrarRegistros() {
    const terminoBusqueda = document.getElementById("busqueda").value.toLowerCase();

    // Filtrar registros según búsqueda
    const registrosFiltrados = registros.filter(reg => {
        return Object.values(reg).some(val =>
            String(val).toLowerCase().includes(terminoBusqueda)
        );
    });

    const inicio = (paginaActual - 1) * registrosPorPagina;
    const fin = inicio + registrosPorPagina;
    const registrosPaginados = registrosFiltrados.slice(inicio, fin);

    tabla.innerHTML = "";

    registrosPaginados.forEach((registro, index) => {
        // El índice original en el array 'registros' para el botón PDF
        const indexOriginal = registros.indexOf(registro);

        let marcasHtml = "";
        let modelosHtml = "";
        let serialsHtml = "";
        let pinsHtml = "";

        if (registro.Tipo === "Acta De Entrega") {
            const equiposList = registro.equipos || [];
            if (equiposList.length > 0) {
                marcasHtml = equiposList.map(e => e.Marca || "").join("<br>");
                modelosHtml = equiposList.map(e => e.Modelo || "").join("<br>");
                serialsHtml = equiposList.map(e => e.Serial || "").join("<br>");
                pinsHtml = equiposList.map(e => e.Pin || "").join("<br>");
            } else {
                marcasHtml = registro.Marca || "";
                modelosHtml = registro.Modelo || "";
                serialsHtml = registro.Serial || "";
                pinsHtml = registro.Pin || "";
            }
        } else if (registro.Tipo === "Acta Componentes") {
            marcasHtml = "-";
            modelosHtml = registro.ModeloComponente || "";
            serialsHtml = registro.SerialComponente || "";
            pinsHtml = "-";
        } else if (registro.Tipo === "Acta Prestamo") {
            marcasHtml = "-";
            modelosHtml = "-";
            serialsHtml = registro.SerialPrestamo || "";
            pinsHtml = "-";
        } else if (registro.Tipo === "Acta De Devolucion") {
            marcasHtml = "-";
            modelosHtml = registro.ModeloDevolucion || "";
            serialsHtml = registro.SerialDevolucion || "";
            pinsHtml = "-";
        } else {
            marcasHtml = registro.Marca || "";
            modelosHtml = registro.Modelo || "";
            serialsHtml = registro.Serial || "";
            pinsHtml = registro.Pin || "";
        }

        tabla.innerHTML += `
            <tr>
                <td>${registro.nombre}</td>
                <td>${registro.fecha}</td>
                <td>${registro.Cargo}</td>
                <td>${registro.Sede}</td>
                <td>${registro.Area}</td>
                <td>${registro.Tipo}</td>
                <td>${marcasHtml}</td>
                <td>${modelosHtml}</td>
                <td>${serialsHtml}</td>
                <td>${pinsHtml}</td>
                <td>
                    <button class="pdf-btn" onclick="generarPDF(${indexOriginal})">
                        PDF
                    </button>
                </td>
            </tr>
        `;
    });

    renderizarPaginacion(registrosFiltrados.length);
}

function renderizarPaginacion(totalRegistros) {
    const contenedorPaginacion = document.getElementById("paginacion");
    const totalPaginas = Math.ceil(totalRegistros / registrosPorPagina);

    contenedorPaginacion.innerHTML = "";

    if (totalPaginas <= 1) return;

    // Botón Anterior
    const btnAnterior = document.createElement("button");
    btnAnterior.innerText = "Anterior";
    btnAnterior.disabled = paginaActual === 1;
    btnAnterior.onclick = () => {
        paginaActual--;
        mostrarRegistros();
    };
    contenedorPaginacion.appendChild(btnAnterior);


    for (let i = 1; i <= totalPaginas; i++) {
        const btnPagina = document.createElement("button");
        btnPagina.innerText = i;
        if (i === paginaActual) btnPagina.classList.add("active");
        btnPagina.onclick = () => {
            paginaActual = i;
            mostrarRegistros();
        };
        contenedorPaginacion.appendChild(btnPagina);
    }


    const btnSiguiente = document.createElement("button");
    btnSiguiente.innerText = "Siguiente";
    btnSiguiente.disabled = paginaActual === totalPaginas;
    btnSiguiente.onclick = () => {
        paginaActual++;
        mostrarRegistros();
    };
    contenedorPaginacion.appendChild(btnSiguiente);
}

function generarPDF(index) {

    const registro = registros[index];

    const { jsPDF } = window.jspdf;

    const doc = new jsPDF("p", "mm", "a4");

    const firmaBastian = "data:image/png;base64,";
    const firmaElias = "data:image/png;base64,";
    const firmaDiego = "data:image/png;base64,";
    const firmaPedro = "data:image/png;base64,";
    const firmaBenjamin = "data:image/png;base64,";

    const firmaMap = {
        "Bastian Palma": firmaBastian,
        "Benjamin Couchot": firmaBenjamin,
        "Elias Escobar": firmaElias,
        "Diego Cisterna": firmaDiego,
        "Pedro Romero": firmaPedro,
    };

    // ===== LOGO BASE64 =====
    const logoBase64 = "data:image/png;base64,";
    doc.addImage(
        logoBase64,
        "PNG",
        10,
        8,
        30,
        17
    );
    // ===== TITULO =====
    doc.setFontSize(16);
    doc.setFont("helvetica", "bold");

    // Determinar título y datos según tipo
    let tituloSuperior = "ACTA ENTREGA";
    let cuerpoEquipo = [];

    if (registro.Tipo === "Acta De Entrega") {
        tituloSuperior = "ACTA ENTREGA";
        cuerpoEquipo = [
            ["Tipo", registro.Tipo, "PIN", registro.Pin || ""],
            ["Marca", registro.Marca || "", "Modelo", registro.Modelo || ""],
            ["Serial", registro.Serial || "", "", ""]
        ];
    } else if (registro.Tipo === "Acta Componentes") {
        tituloSuperior = "ACTA COMPONENTES";
        cuerpoEquipo = [
            ["Tipo", registro.Tipo, "Dispositivo", registro.Dispositivo || ""],
            ["Modelo", registro.ModeloComponente || "", "Serial", registro.SerialComponente || ""],
            ["", "", "", ""]
        ];
    } else if (registro.Tipo === "Acta Prestamo") {
        tituloSuperior = "ACTA PRÉSTAMO";
        cuerpoEquipo = [
            ["Tipo", registro.Tipo, "Dispositivo", registro.DispositivoPrestamo || ""],
            ["Fecha Devolucion", formatearFecha(registro.FechaDevolucion), "Serial", registro.SerialPrestamo || ""],
            ["", "", "", ""]
        ];
    } else if (registro.Tipo === "Acta De Devolucion") {
        tituloSuperior = "ACTA DEVOLUCIÓN";
        cuerpoEquipo = [
            ["Tipo", registro.Tipo, "Equipo/Dispositivo", registro.EquipoDevolucion || ""],
            ["Modelo", registro.ModeloDevolucion || "", "Serial", registro.SerialDevolucion || ""],
            ["", "", "", ""]
        ];
    }

    // Obtenemos el número y lo unimos al título
    const numeroActaPDF = obtenerNumeroActa(registro);
    const textoCompleto = `${tituloSuperior} N° ${numeroActaPDF}`;

    // Lo posicionamos a la derecha para que coincida con el logo a la izquierda
    doc.text(textoCompleto, 195, 15, { align: "right" });


    // ===== TEXTO =====
    doc.setFontSize(9);
    doc.setFont("helvetica", "normal");

    doc.text(
        "Certifico que los elementos detallados en el presente documento me han sido entregados para mi cuidado y custodia.",
        20,
        38,
        { maxWidth: 170 }
    );

    // ===== DATOS FUNCIONARIO =====
    doc.autoTable({
        startY: 45,

        head: [
            [
                {
                    content: "Datos funcionario",
                    colSpan: 4,
                    styles: {
                        halign: "center",
                        fillColor: [0, 55, 123],
                        textColor: [255, 255, 255]
                    }
                }
            ]
        ],

        body: [

            [
                "Nombre",
                registro.nombre,
                "Fecha",
                formatearFecha(registro.fecha)
            ],

            [
                "Cargo",
                registro.Cargo,
                "Sede",
                registro.Sede
            ],

            [
                "Área",
                { content: registro.Area, colSpan: 3 }
            ]
        ],

        styles: {
            fontSize: 9,
            cellPadding: 2,
            lineColor: [150, 150, 150],
            lineWidth: 0.1
        },
        theme: 'grid'
    });

    // ===== DATOS EQUIPO =====
    if (registro.Tipo === "Acta De Entrega") {
        let bodyEquipos = [];
        const listaEquipos = registro.equipos || [];

        if (listaEquipos.length > 0) {
            listaEquipos.forEach(eq => {
                bodyEquipos.push([
                    eq.Dispositivo || "PC",
                    eq.Marca || "",
                    eq.Modelo || "",
                    eq.Serial || "",
                    eq.Pin || ""
                ]);
            });
        } else {
            // Compatibilidad con registros antiguos
            bodyEquipos.push([
                registro.DispositivoEntrega || "PC",
                registro.Marca || "",
                registro.Modelo || "",
                registro.Serial || "",
                registro.Pin || ""
            ]);
        }

        doc.autoTable({
            startY: doc.lastAutoTable.finalY + 5,
            head: [
                [
                    {
                        content: "Datos de equipo",
                        colSpan: 5,
                        styles: {
                            halign: "center",
                            fillColor: [0, 55, 123],
                            textColor: [255, 255, 255]
                        }
                    }
                ],
                [
                    { content: "Equipo", styles: { fillColor: [0, 55, 123], textColor: [255, 255, 255], halign: "center" } },
                    { content: "Marca", styles: { fillColor: [0, 55, 123], textColor: [255, 255, 255], halign: "center" } },
                    { content: "Modelo", styles: { fillColor: [0, 55, 123], textColor: [255, 255, 255], halign: "center" } },
                    { content: "Serial", styles: { fillColor: [0, 55, 123], textColor: [255, 255, 255], halign: "center" } },
                    { content: "PIN", styles: { fillColor: [0, 55, 123], textColor: [255, 255, 255], halign: "center" } }
                ]
            ],
            body: bodyEquipos,
            styles: {
                fontSize: 9,
                cellPadding: 2,
                lineColor: [150, 150, 150],
                lineWidth: 0.1,
                halign: "center"
            },
            theme: 'grid'
        });
    } else {
        doc.autoTable({
            startY: doc.lastAutoTable.finalY + 5,
            head: [
                [
                    {
                        content: "Datos de equipo",
                        colSpan: 4,
                        styles: {
                            halign: "center",
                            fillColor: [0, 55, 123],
                            textColor: [255, 255, 255]
                        }
                    }
                ]
            ],
            body: cuerpoEquipo,
            styles: {
                fontSize: 9,
                cellPadding: 2,
                lineColor: [150, 150, 150],
                lineWidth: 0.1
            },
            theme: 'grid'
        });
    }

    // ===== OBSERVACIONES =====
    doc.autoTable({

        startY: doc.lastAutoTable.finalY + 5,

        head: [
            [
                {
                    content: "Observaciones",
                    colSpan: 1,
                    styles: {
                        halign: "center",
                        fillColor: [0, 55, 123],
                        textColor: [255, 255, 255]
                    }
                }
            ]
        ],

        body: [
            [registro.observaciones]
        ],

        styles: {
            fontSize: 9,
            cellPadding: 4,
            lineColor: [150, 150, 150],
            lineWidth: 0.1
        },
        theme: 'grid'

    });

    // ===== FIRMAS =====
    doc.autoTable({

        startY: doc.lastAutoTable.finalY + 15,

        head: [[{
            content: "Aprobado por",
            colSpan: 2,
            styles: {
                halign: "center",
                fillColor: [0, 55, 123],
                textColor: [255, 255, 255]
            }
        }]],

        body: [
            // Bastian Palma – static (kept for historic data)
            ["Jefatura\nBASTIAN PALMA", "\n\n\nFirma"],

            // Técnico que entrega – dynamic
            [`Quién entrega\n${registro.Tecnico || ""}`, "\n\n\nFirma"],

            // Cliente que recibe
            [`Quién recepciona\n${registro.nombre}`, "\n\n\nFirma"]
        ],

        styles: {
            fontSize: 9,
            cellPadding: 8,
            halign: "center",
            lineColor: [150, 150, 150],
            lineWidth: 0.1
        },

        theme: 'grid',

        /*** NEW – draw the correct signature ***/
        didDrawCell: function (data) {
            // We only care about the second column (the one that should contain the signature)
            if (data.column.index !== 1) return;

            // Determine which signature we need
            let signature = null;

            // Row 0 → Bastian (kept unchanged)
            if (data.row.index === 0) {
                signature = firmaBastian;
            }

            // Row 1 → the selected technician
            if (data.row.index === 1) {
                const techName = registro.Tecnico?.trim();
                if (techName && firmaMap[techName]) {
                    signature = firmaMap[techName];
                }
            }

            // If we have a signature, add it to the cell
            if (signature) {
                const cell = data.cell;
                const imgWidth = 25;           // keep the same size as before
                const imgHeight = 12;
                const x = cell.x + (cell.width - imgWidth) / 2;
                const y = cell.y + 4;

                doc.addImage(signature, 'PNG', x, y, imgWidth, imgHeight);
            }
        },
    });

    // ===== DESCARGAR PDF =====
    doc.save(`Acta_${registro.nombre}.pdf`);
};     